import java.util.*;

public class Solution {
    private static Map<Integer, List<Integer>> graph;
    private static String label;
    private static Map<Long, Integer> memo;

    public static long solve(long n, long[][] edges, String label) {
        Solution.graph = new HashMap<>();
        Solution.label = label;
        Solution.memo = new HashMap<>();

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            graph.computeIfAbsent(u, k -> new ArrayList<>()).add(v);
            graph.computeIfAbsent(v, k -> new ArrayList<>()).add(u);
        }

        int maxLen = 1;
        for (int start = 0; start < n; start++) {
            int mask = 1 << start;
            maxLen = Math.max(maxLen, dfs(start, mask));
        }
        return maxLen;
    }

    private static int dfs(int node, int mask) {
        long key = ((long) node << 14) | mask;
        if (memo.containsKey(key)) {
            return memo.get(key);
        }

        // Check current path's palindrome status
        int[] freq = new int[26];
        for (int i = 0; i < 14; i++) {
            if ((mask & (1 << i)) != 0) {
                freq[label.charAt(i) - 'a']++;
            }
        }
        int oddCount = 0;
        for (int count : freq) {
            if (count % 2 != 0) {
                oddCount++;
            }
        }
        int currentLen = Integer.bitCount(mask);
        int res = (oddCount <= 1) ? currentLen : 0;

        // Explore neighbors
        if (graph.containsKey(node)) {
            for (int neighbor : graph.get(node)) {
                if ((mask & (1 << neighbor)) == 0) {
                    int newMask = mask | (1 << neighbor);
                    res = Math.max(res, dfs(neighbor, newMask));
                }
            }
        }

        memo.put(key, res);
        return res;
    }
}
